let table = {{workflowparams:data}};

if(table.purchase_invoice_no_type !== -9999 && (
  !table.purchase_invoice_no || table.purchase_invoice_no === null || table.purchase_invoice_no === ''
)) {
  table.purchase_invoice_no = 'draft'
}

table.pi_status = 'Draft';

return { table };

return {
  required_fields: JSON.stringify([
  { name: "plant_id", label: "Plant" },
  { name: "purchase_invoice_no", label: "Purchase Invoice Number" },
  {
    name: "table_pi",
    label: "Item Information",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    plant_id: {{node:code_pi_draft_docno.data.table.plant_id}},
    purchase_invoice_no: {{node:code_pi_draft_docno.data.table.purchase_invoice_no}},
    table_pi: {{node:code_pi_draft_docno.data.table.table_pi}}
  })
}

let table = {{workflowparams:data}}

if (
  table.purchase_invoice_no_type !== -9999 &&
  (!table.purchase_invoice_no ||
    table.purchase_invoice_no === null ||
    table.purchase_invoice_no === "" ||
    table.previous_status === "Draft")
) {
  table.purchase_invoice_no = 'issued'
}

table.pi_status = 'Completed';

return { table };

return {
  required_fields: JSON.stringify([
  { name: "plant_id", label: "Plant" },
  { name: "purchase_invoice_no", label: "Purchase Invoice Number" },
  { name: "invoice_date", label: "Invoice Date" },
  { name: "pi_description", label: "Description" },
  {
    name: "table_pi",
    label: "PI Items",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    plant_id: {{node:code_pi_docno.data.table.plant_id}},
    purchase_invoice_no: {{node:code_pi_docno.data.table.purchase_invoice_no}},
    invoice_date: {{node:code_pi_docno.data.table.invoice_date}},
    pi_description: {{node:code_pi_docno.data.table.pi_description}},
    table_pi: {{node:code_pi_docno.data.table.table_pi}}
  })
}

let entry = {{node:code_pi_docno.data.table}};
const totalQuantity = entry.table_pi.reduce((sum, item) => {
    const { invoice_qty } = item;
    return sum + (invoice_qty || 0);
  }, 0);

if (totalQuantity === 0) {
  return {
    entry: {},
    status: 'Failed',
    code: 407,
    message: 'Total invoiced quantity is 0.'
  }
}

entry.table_pi = entry.table_pi.filter((item) => item.invoice_qty > 0);
let poID = [];
let grID = [];
let purchaseOrderNumber = [];
let goodsReceivingNumber = [];
for(const pi of entry.table_pi) {
  if(pi.line_gr_id && pi.line_gr_id !== "") {
    grID.push(pi.line_gr_id);
    goodsReceivingNumber.push(pi.goods_receiving_no);
  }

  poID.push(pi.line_po_id);
  purchaseOrderNumber.push(pi.purchase_order_no);
}

poID = [...new Set(poID)];
grID = [...new Set(grID)];
purchaseOrderNumber = [...new Set(purchaseOrderNumber)];
goodsReceivingNumber = [...new Set(goodsReceivingNumber)];

entry.po_id = poID;
entry.gr_id = grID;
entry.po_no_display = purchaseOrderNumber.join(", ");
entry.gr_no_display = goodsReceivingNumber.join(", ");

return {
  entry: entry,
  status: 'Success',
  code: 200,
  message: ''
};

let entry = {{node:code_pi_draft_docno.data.table}} || {{node:code_pi_checkqty.data.entry}}

for (const [index, piLineItem] of entry.table_pi.entries()) {
  piLineItem.supplier_id = entry.supplier_name || null;
  piLineItem.plant_id = entry.plant_id || null;
  piLineItem.payment_term_id = entry.invoice_payment_term_id || null;
  piLineItem.billing_state_id = entry.billing_address_state || null;
  piLineItem.billing_country_id = entry.billing_address_country || null;
  piLineItem.shipping_state_id = entry.shipping_address_state || null;
  piLineItem.shipping_country_id = entry.shipping_address_country || null;
  piLineItem.line_index = index + 1;
  piLineItem.agent_id = entry.agent_id;
}

entry.posted_status = entry.pi_status === 'Draft' ? '' : 'Unposted';

return { entry };

const poList = {{node:search_node_po.data.data}} || [];
const grList = {{node:search_node_gr.data.data}} || [];
const data = {{node:code_pi_fillback.data.entry}};
let allErrors = [];

const roundTo3 = (value) => Math.round((parseFloat(value) || 0) * 1000) / 1000;

const validateInvoiceQuantities = (items, tablePi, docId, docIdKey, piLineIdKey, qtyKey, excludeGRLines) => {
  const filteredPI = tablePi.filter((item) => item[docIdKey] === docId && (!excludeGRLines || !item.line_gr_id || item.line_gr_id === ""));
  const errors = [];
  filteredPI.forEach((piItem) => {
    const originalItem = items.find((item) => item.id === piItem[piLineIdKey]);
    if (originalItem) {
      const availableQty = roundTo3(originalItem[qtyKey]);
      const currentInvoicedQty = roundTo3(originalItem.invoice_qty);
      const newInvoiceQty = roundTo3(piItem.invoice_qty);
      const totalInvoicedQty = roundTo3(currentInvoicedQty + newInvoiceQty);
      if (totalInvoicedQty > availableQty) {
        errors.push({
          itemName: originalItem.material_id || originalItem.material_name || `Item ${originalItem.id}`,
        });
      }
    }
  });
  return errors;
};

const poIds = Array.isArray(data.po_id) ? data.po_id : [data.po_id];
for (const poID of poIds) {
  const poData = poList.find((po) => po.id === poID);
  if (!poData) continue;
  const poItems = poData.table_po || [];
  allErrors = [...allErrors, ...validateInvoiceQuantities(poItems, data.table_pi, poData.id, "line_po_id", "po_line_id", "quantity", true)];
}

if (data.gr_id && data.gr_id.length > 0) {
  const grIds = Array.isArray(data.gr_id) ? data.gr_id : [data.gr_id];
  for (const grID of grIds) {
    const grData = grList.find((gr) => gr.id === grID);
    if (!grData) continue;
    const grItems = grData.table_gr || [];
    allErrors = [...allErrors, ...validateInvoiceQuantities(grItems, data.table_pi, grData.id, "line_gr_id", "gr_line_id", "received_qty")];
  }
}

return {
  status: allErrors.length > 0 ? 'Failed' : 'Success',
  allErrors
};

const errMsg = {{node:code_pi_validate.data.allErrors}}.map((err) => err.itemName).join(', ')

return {
 message: `${errMsg} invoice quantity exceed available invoice quantity.`
}

const poList = {{node:search_node_po.data.data}} || [];
const grList = {{node:search_node_gr.data.data}} || [];
const data = {{node:code_pi_fillback.data.entry}};

const roundTo3 = (value) => Math.round((parseFloat(value) || 0) * 1000) / 1000;

const processItems = (items, tablePi, docId, docIdKey, piLineIdKey, qtyKey) => {
  const filteredPI = tablePi.filter((item) => item[docIdKey] === docId);

  const countableItems = items.filter((item) => item.parent_or_child !== "Child");
  let totalItems = countableItems.length;
  let partiallyInvoicedItems = 0;
  let fullyInvoicedItems = 0;

  const updatedItems = items.map((item) => {
    const matchedPI = filteredPI.find((pi) => pi[piLineIdKey] === item.id);
    if (matchedPI) {
      const piInvoicedQty = roundTo3(matchedPI.invoice_qty);
      const currentInvoicedQty = roundTo3(item.invoice_qty);
      const totalInvoicedQty = roundTo3(currentInvoicedQty + piInvoicedQty);
      return { ...item, invoice_qty: totalInvoicedQty };
    }
    return { ...item };
  });

  for (const [index, item] of updatedItems.entries()) {
    if (item.parent_or_child === "Child") continue;
    if (roundTo3(item.invoice_qty) > 0) {
      partiallyInvoicedItems++;
      updatedItems[index].pi_status = "Partially Invoiced";
      if (roundTo3(item.invoice_qty) >= roundTo3(item[qtyKey] || 0)) {
        fullyInvoicedItems++;
        updatedItems[index].pi_status = "Fully Invoiced";
      }
    }
  }

  const allItemsComplete = fullyInvoicedItems === totalItems;
  const anyItemProcessing = partiallyInvoicedItems > 0;
  let newPIStatus = anyItemProcessing
    ? allItemsComplete
      ? "Fully Invoiced"
      : "Partially Invoiced"
    : "";

  return { updatedItems, newPIStatus };
};

const poIds = Array.isArray(data.po_id) ? data.po_id : [data.po_id];
let updatedPO = [];
for (const poID of poIds) {
  const poData = poList.find((po) => po.id === poID);
  if (!poData) continue;
  const poItems = poData.table_po || [];
  const { updatedItems, newPIStatus } = processItems(poItems, data.table_pi, poData.id, "line_po_id", "po_line_id", "quantity");
  updatedPO.push({ po_id: poData.id, pi_status: newPIStatus, table_po: updatedItems });
}

let updatedGR = [];
if (data.gr_id && data.gr_id.length > 0) {
  const grIds = Array.isArray(data.gr_id) ? data.gr_id : [data.gr_id];
  for (const grID of grIds) {
    const grData = grList.find((gr) => gr.id === grID);
    if (!grData) continue;
    const grItems = grData.table_gr || [];
    const { updatedItems, newPIStatus } = processItems(grItems, data.table_pi, grData.id, "line_gr_id", "gr_line_id", "received_qty");
    updatedGR.push({ gr_id: grData.id, pi_status: newPIStatus, table_gr: updatedItems });
  }
}

return { updatedPO, updatedGR };
